/**
 * @generated by @flusk/cli
 * Training pairs subcommand
 */
import chalk from 'chalk';
import { createSqliteStorage } from '@flusk/resources';

// --- BEGIN CUSTOM ---
interface PairsOpts {
  model?: string;
  limit: string;
}

export function trainingPairsAction(opts: PairsOpts): void {
  const storage = createSqliteStorage();
  const limit = parseInt(opts.limit, 10);

  const pairs = opts.model
    ? storage.trainingPairs.listByModel(opts.model, limit, 0)
    : storage.trainingPairs.list(limit, 0);

  if (pairs.length === 0) {
    console.log(chalk.dim('No training pairs found.'));
    return;
  }

  console.log(chalk.bold('\n📝 Training Pairs\n'));
  const header = [
    pad('ID', 10), pad('Model', 25), pad('Quality', 10),
    pad('In Tok', 8), pad('Out Tok', 8), pad('Cluster', 15),
  ].join('  ');
  console.log(chalk.bold(header));
  console.log(chalk.dim('─'.repeat(80)));

  for (const p of pairs) {
    const row = [
      pad(p.id.slice(0, 8), 10),
      pad(p.sourceModel, 25),
      pad(p.quality, 10),
      pad(String(p.inputTokens), 8),
      pad(String(p.outputTokens), 8),
      pad(p.cluster ?? '-', 15),
    ].join('  ');
    console.log(row);
  }
  console.log();
}

function pad(s: string, len: number): string {
  return s.length >= len ? s.slice(0, len) : s + ' '.repeat(len - s.length);
}
// --- END CUSTOM ---
